import sys

class Solution:
    def solve(self, s: str) -> int:
        # remove leading whitespace
        i = 0
        n = len(s)
        while i < n and s[i].isspace():
            i += 1
        # sign
        sign = 1
        if i < n and (s[i] == '+' or s[i] == '-'):
            if s[i] == '-':
                sign = -1
            i += 1
        # recursive parsing of digits
        def rec(idx: int, acc: int) -> int:
            if idx >= n or not s[idx].isdigit():
                return acc
            digit = ord(s[idx]) - ord('0')
            # check overflow before multiplying
            if acc > (2**31 - 1 - digit) // 10:
                # overflow will happen, return clamped value directly
                return 2**31 if sign == 1 else -2**31
            return rec(idx + 1, acc * 10 + digit)
        val = rec(i, 0)
        # if overflow was detected inside recursion, val already clamped
        if val == 2**31:
            return 2**31 - 1
        if val == -2**31:
            return -2**31
        result = sign * val
        # final clamp
        if result < -2**31:
            return -2**31
        if result > 2**31 - 1:
            return 2**31 - 1
        return result

if __name__ == '__main__':
    data = sys.stdin.read().split('\n')
    if len(data) < 2:
