#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int solve(string s) {
        int n = s.size();
        int i = 0;
        // skip leading whitespace
        while (i < n && isspace(static_cast<unsigned char>(s[i]))) i++;
        // sign
        int sign = 1;
        if (i < n && (s[i] == '+' || s[i] == '-')) {
            if (s[i] == '-') sign = -1;
            i++;
        }
        // recursive function using lambda
        function<long long(int,long long)> rec = [&](int idx, long long acc) -> long long {
            if (idx >= n || !isdigit(static_cast<unsigned char>(s[idx]))) return acc;
            int digit = s[idx] - '0';
            // overflow check
            if (acc > (LLONG_MAX - digit) / 10) {
                return sign == 1 ? (long long)INT_MAX + 1 : (long long)INT_MIN - 1; // sentinel beyond bounds
            }
            return rec(idx + 1, acc * 10 + digit);
        };
        long long val = rec(i, 0);
        // handle sentinel overflow
        if (val == (long long)INT_MAX + 1) return INT_MAX;
        if (val == (long long)INT_MIN - 1) return INT_MIN;
        long long result = sign * val;
        if (result < INT_MIN) return INT_MIN;
        if (result > INT_MAX) return INT_MAX;
        return (int)result;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int N;
    if (!(cin >> N)) return 0;
    string dummy;
    getline(cin, dummy); // consume endline after N
    string s;
    getline(cin, s);
    // s may be shorter or longer than N, but we trust input
    Solution sol;
    int ans = sol.solve(s);
    cout << ans << "\n";
    return 0;
}
